# Category: serverless_security

import os
from google.cloud import storage, pubsub_v1, firestore

def process_file(event, context):
    """Cloud function triggered by a new file in bucket"""

    bucket_name = event['bucket']
    source_blob_name = event['name']
    destination_file_name = f"/tmp/{source_blob_name}"

    client = storage.Client()
    bucket = client.get_bucket(bucket_name)
    blob = bucket.blob(source_blob_name)
    blob.download_to_filename(destination_file_name)

    firestore_client = firestore.Client()

    # Write a new document to Firestore
    doc_ref = firestore_client.collection('files').document('filedata')
    doc_ref.set({
        'filename': source_blob_name,
        'bucket': bucket_name
    })

    # Publish a message to Pub/Sub
    publisher = pubsub_v1.PublisherClient()
    topic_name = 'projects/{project_id}/topics/{topic}'.format(project_id=os.getenv('GOOGLE_CLOUD_PROJECT'), topic='new_files')
    publisher.publish(topic_name, b'New file', filename=source_blob_name, bucket=bucket_name)